import json
import re

# Load books data with extracted years
books_file = locals()['var_functions.query_db:14']
with open(books_file, 'r') as f:
    books_data = json.load(f)

# Load reviews data
reviews_file = locals()['var_functions.query_db:22']
with open(reviews_file, 'r') as f:
    reviews_data = json.load(f)

# Function to extract publication year from details text
def extract_year(details_text):
    if not details_text:
        return None

    patterns = [
        r'published on [A-Za-z]+ \d+, (\d{4})',
        r'released on [A-Za-z]+ \d+, (\d{4})',
        r'published by [^,]+ on [A-Za-z]+ \d+, (\d{4})',
        r'first edition released on [A-Za-z]+ \d+, (\d{4})',
        r'published in [A-Za-z]+ (\d{4})',
        r'published by [^,]+ in [A-Za-z]+ (\d{4})',
        r'published on (\d{4})-\d{2}-\d{2}',
        r'first edition on [A-Za-z]+ \d+, (\d{4})',
    ]

    for pattern in patterns:
        match = re.search(pattern, details_text, re.IGNORECASE)
        if match:
            if len(match.groups()) >= 1:
                year_str = match.group(1)
                if year_str.isdigit() and len(year_str) == 4:
                    year = int(year_str)
                    if 1900 <= year <= 2024:
                        return year

    # Try to find any 4-digit year in the text
    year_match = re.search(r'(\d{4})', details_text)
    if year_match:
        year = int(year_match.group(1))
        if 1900 <= year <= 2024:
            return year

    return None

# Create books dictionary with decade info
books_dict = {}
for book in books_data:
    year = extract_year(book['details'])
    if year:
        decade = f"{(year // 10) * 10}s"
        books_dict[book['book_id']] = {
            'year': year,
            'decade': decade,
            'has_ratings': int(book['rating_number']) > 0 if book['rating_number'].isdigit() else False
        }

# Map reviews to books by purchase_id -> book_id mapping
# purchase_id format: purchaseid_X should map to bookid_X
review_ratings_by_book = {}
for review in reviews_data:
    purchase_id = review['purchase_id']
    # Extract the number part from purchase_id
    match = re.search(r'purchaseid_(\d+)', purchase_id)
    if match:
        book_num = match.group(1)
        book_id = f"bookid_{book_num}"

        if book_id in books_dict:
            if book_id not in review_ratings_by_book:
                review_ratings_by_book[book_id] = []
            try:
                rating = float(review['rating'])
                review_ratings_by_book[book_id].append(rating)
            except (ValueError, TypeError):
                continue

# Calculate decade statistics
decade_stats = {}
for book_id, ratings in review_ratings_by_book.items():
    if book_id in books_dict:
        decade = books_dict[book_id]['decade']
        if decade not in decade_stats:
            decade_stats[decade] = {
                'total_books': 0,
                'total_ratings': 0,
                'sum_ratings': 0.0,
                'book_ids': set()
            }

        decade_stats[decade]['total_books'] += 1
        decade_stats[decade]['book_ids'].add(book_id)
        decade_stats[decade]['total_ratings'] += len(ratings)
        decade_stats[decade]['sum_ratings'] += sum(ratings)

# Filter decades with at least 10 distinct books and calculate averages
valid_decade_averages = {}
for decade, stats in decade_stats.items():
    num_books = len(stats['book_ids'])
    if num_books >= 10:
        avg_rating = stats['sum_ratings'] / stats['total_ratings'] if stats['total_ratings'] > 0 else 0
        valid_decade_averages[decade] = {
            'num_books': num_books,
            'total_ratings': stats['total_ratings'],
            'avg_rating': round(avg_rating, 3)
        }

# Sort by average rating descending
sorted_decades = sorted(valid_decade_averages.items(), key=lambda x: x[1]['avg_rating'], reverse=True)

result = {
    'valid_decades_with_min_10_books': valid_decade_averages,
    'ranked_decades': sorted_decades,
    'top_decade': sorted_decades[0] if sorted_decades else None
}

print("__RESULT__:")
print(json.dumps(result))

